import hmac
import hashlib
import base64
import time
import struct
import io
import qrcode
from urllib.parse import quote


class TOTPManager:
    def __init__(self, issuer="MyApp", digits=6, period=30, algorithm='SHA1'):
        self.issuer = issuer
        self.digits = digits
        self.period = period
        self.algorithm = algorithm.upper()
        
    def generate_secret(self, length=32):
        import secrets
        alphabet = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ234567'
        secret = ''.join(secrets.choice(alphabet) for _ in range(length))
        return secret
    
    def _get_hotp_token(self, secret, counter):
        key = base64.b32decode(secret.upper() + '=' * ((8 - len(secret)) % 8))
        
        counter_bytes = struct.pack('>Q', counter)
        
        if self.algorithm == 'SHA1':
            hash_func = hashlib.sha1
        elif self.algorithm == 'SHA256':
            hash_func = hashlib.sha256
        elif self.algorithm == 'SHA512':
            hash_func = hashlib.sha512
        else:
            hash_func = hashlib.sha1
            
        hmac_hash = hmac.new(key, counter_bytes, hash_func).digest()
        
        offset = hmac_hash[-1] & 0x0F
        
        truncated_hash = hmac_hash[offset:offset + 4]
        
        code = struct.unpack('>I', truncated_hash)[0] & 0x7FFFFFFF
        
        code = code % (10 ** self.digits)
        
        return str(code).zfill(self.digits)
    
    def get_totp_token(self, secret, timestamp=None):
        if timestamp is None:
            timestamp = time.time()
        
        counter = int(timestamp) // self.period
        
        return self._get_hotp_token(secret, counter)
    
    def verify_totp(self, secret, token, timestamp=None, window=1):
        if timestamp is None:
            timestamp = time.time()
        
        counter = int(timestamp) // self.period
        
        for i in range(-window, window + 1):
            expected_token = self._get_hotp_token(secret, counter + i)
            if expected_token == token:
                return True
        
        return False
    
    def get_provisioning_uri(self, secret, account_name, issuer=None):
        if issuer is None:
            issuer = self.issuer
        
        algorithm_param = f'&algorithm={self.algorithm}' if self.algorithm != 'SHA1' else ''
        digits_param = f'&digits={self.digits}' if self.digits != 6 else ''
        period_param = f'&period={self.period}' if self.period != 30 else ''
        
        uri = f'otpauth://totp/{quote(issuer)}:{quote(account_name)}?secret={secret}&issuer={quote(issuer)}{algorithm_param}{digits_param}{period_param}'
        
        return uri
    
    def generate_qr_code(self, secret, account_name, issuer=None):
        uri = self.get_provisioning_uri(secret, account_name, issuer)
        
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(uri)
        qr.make(fit=True)
        
        img = qr.make_image(fill_color="black", back_color="white")
        
        return img
    
    def save_qr_code(self, secret, account_name, filename, issuer=None):
        img = self.generate_qr_code(secret, account_name, issuer)
        img.save(filename)
        return filename
    
    def get_qr_code_bytes(self, secret, account_name, issuer=None):
        img = self.generate_qr_code(secret, account_name, issuer)
        
        img_bytes = io.BytesIO()
        img.save(img_bytes, format='PNG')
        img_bytes.seek(0)
        
        return img_bytes.getvalue()


class UserTOTP:
    def __init__(self, username, secret=None, totp_manager=None):
        self.username = username
        self.totp_manager = totp_manager if totp_manager else TOTPManager()
        
        if secret is None:
            self.secret = self.totp_manager.generate_secret()
        else:
            self.secret = secret
        
        self.backup_codes = []
        self.is_verified = False
    
    def generate_backup_codes(self, count=10):
        import secrets
        self.backup_codes = [
            '-'.join([
                ''.join(secrets.choice('0123456789') for _ in range(4))
                for _ in range(2)
            ])
            for _ in range(count)
        ]
        return self.backup_codes
    
    def use_backup_code(self, code):
        if code in self.backup_codes:
            self.backup_codes.remove(code)
            return True
        return False
    
    def get_current_token(self):
        return self.totp_manager.get_totp_token(self.secret)
    
    def verify_token(self, token, window=1):
        return self.totp_manager.verify_totp(self.secret, token, window=window)
    
    def get_qr_code(self):
        return self.totp_manager.generate_qr_code(self.secret, self.username)
    
    def save_qr_code(self, filename):
        return self.totp_manager.save_qr_code(self.secret, self.username, filename)
    
    def get_provisioning_uri(self):
        return self.totp_manager.get_provisioning_uri(self.secret, self.username)
    
    def enable_totp(self, verification_token):
        if self.verify_token(verification_token):
            self.is_verified = True
            return True
        return False


class TOTPAuthSystem:
    def __init__(self, issuer="MyApp"):
        self.totp_manager = TOTPManager(issuer=issuer)
        self.users = {}
    
    def register_user(self, username):
        if username in self.users:
            return None
        
        user_totp = UserTOTP(username, totp_manager=self.totp_manager)
        self.users[username] = user_totp
        
        return user_totp
    
    def get_user(self, username):
        return self.users.get(username)
    
    def setup_totp_for_user(self, username):
        user = self.get_user(username)
        if not user:
            user = self.register_user(username)
        
        provisioning_uri = user.get_provisioning_uri()
        backup_codes = user.generate_backup_codes()
        
        return {
            'secret': user.secret,
            'provisioning_uri': provisioning_uri,
            'backup_codes': backup_codes,
            'qr_code': user.get_qr_code()
        }
    
    def verify_user_token(self, username, token, allow_backup_codes=True):
        user = self.get_user(username)
        if not user:
            return False
        
        if user.verify_token(token):
            return True
        
        if allow_backup_codes and user.use_backup_code(token):
            return True
        
        return False
    
    def enable_totp_for_user(self, username, verification_token):
        user = self.get_user(username)
        if not user:
            return False
        
        return user.enable_totp(verification_token)
    
    def is_totp_enabled(self, username):
        user = self.get_user(username)
        if not user:
            return False
        return user.is_verified


